{"symbol":"Users-naman-Documents-QBApps-qbapi.app.Services.InvoiceNumberService.InvoiceNumberService.validateInputs","qualified_name":"Users-naman-Documents-QBApps-qbapi.app.Services.InvoiceNumberService.InvoiceNumberService.validateInputs","label":"Method","pagerank":0.00005514205190802565,"is_key_symbol":false,"definition":{"file_path":"app/Services/InvoiceNumberService.php","start_line":107,"end_line":152,"signature":"($storeID, $isNoCharge, $isRefund, $isNoInvoiceSale, $storeDetail, $today)","source":"	private function validateInputs($storeID, $isNoCharge, $isRefund, $isNoInvoiceSale, $storeDetail, $today)
	{
		if (empty($storeID) || !is_numeric($storeID)) {
			return [
				'valid' => false,
				'message' => 'Invalid store ID provided'
			];
		}

		if (!in_array($isNoCharge, [0, 1])) {
			return [
				'valid' => false,
				'message' => 'Invalid isNoCharge value, must be 0 or 1'
			];
		}

		if (!in_array($isRefund, [0, 1])) {
			return [
				'valid' => false,
				'message' => 'Invalid isRefund value, must be 0 or 1'
			];
		}

		if (!in_array($isNoInvoiceSale, [0, 1])) {
			return [
				'valid' => false,
				'message' => 'Invalid isNoInvoiceSale value, must be 0 or 1'
			];
		}

		if (empty($storeDetail) || !is_array($storeDetail)) {
			return [
				'valid' => false,
				'message' => 'Invalid store detail provided'
			];
		}

		if (empty($today) || !preg_match('/^\d{4}-\d{2}-\d{2}$/', $today)) {
			return [
				'valid' => false,
				'message' => 'Invalid date format, expected Y-m-d'
			];
		}

		return ['valid' => true];
	}
