{"symbol":"Users-naman-Documents-QBApps-qbapi.app.Services.InvoiceNumberService.InvoiceNumberService.validateStorePrefixes","qualified_name":"Users-naman-Documents-QBApps-qbapi.app.Services.InvoiceNumberService.InvoiceNumberService.validateStorePrefixes","label":"Method","pagerank":0.00005514205190802565,"is_key_symbol":false,"definition":{"file_path":"app/Services/InvoiceNumberService.php","start_line":72,"end_line":94,"signature":"($storeDetail, $isNoCharge, $isRefund, $isNoInvoiceSale)","source":"	private function validateStorePrefixes($storeDetail, $isNoCharge, $isRefund, $isNoInvoiceSale)
	{
		// Determine required prefix based on order type
		if ($isRefund == 1) {
			if ($isNoInvoiceSale == 1) {
				$requiredPrefix = 'RWICustomStoreOrderPrefix';
			} else {
				$requiredPrefix = $isNoCharge == 1 ? 'NCRefundCustomStoreOrderPrefix' : 'refundCustomStoreOrderPrefix';
			}
		} else {
			$requiredPrefix = $isNoCharge == 1 ? 'NCCustomStoreOrderPrefix' : 'customStoreOrderPrefix';
		}

		// Note: Empty prefixes are allowed, but the field should exist
		if (!array_key_exists($requiredPrefix, $storeDetail)) {
			return [
				'valid' => false,
				'message' => "Missing required store prefix: {$requiredPrefix}"
			];
		}

		return ['valid' => true];
	}
