{"symbol":"Users-naman-Documents-QBApps-qbapi.app.Services.InvoiceNumberService.InvoiceNumberService.getInvoiceNumberSeparator","qualified_name":"Users-naman-Documents-QBApps-qbapi.app.Services.InvoiceNumberService.InvoiceNumberService.getInvoiceNumberSeparator","label":"Method","pagerank":0.00005514205190802565,"is_key_symbol":false,"definition":{"file_path":"app/Services/InvoiceNumberService.php","start_line":51,"end_line":61,"signature":"($storeDetail)","source":"	private function getInvoiceNumberSeparator($storeDetail)
	{
		// Check if custom separator is defined in store settings
		if (isset($storeDetail['invoiceNumberSeparator'])) {
			// Allow empty string as a valid separator (no separator)
			return $storeDetail['invoiceNumberSeparator'];
		}

		// Default separator
		return '-';
	}
