{"symbol":"resetServerGeneratedInvoiceSequences","qualified_name":"Users-naman-Documents-QBApps-qbapi.app.Services.FiscalYearManager.FiscalYearManager.resetServerGeneratedInvoiceSequences","label":"Method","pagerank":0.00005278182381952052,"is_key_symbol":false,"definition":{"file_path":"app/Services/FiscalYearManager.php","start_line":584,"end_line":660,"signature":"($chainID, $fiscalResetDate)","source":"	public function resetServerGeneratedInvoiceSequences($chainID, $fiscalResetDate) {
		return $this->dbManager->executeWithRetry(function () use ($chainID, $fiscalResetDate) {
			$chainSettingsTable = Constants::getGlobalTableName("chainSettings");
			$listOfStoresTable = Constants::getGlobalTableName("listOfStores");
			$invoiceSequenceTable = Constants::getChainTableName($chainID, "invoiceSequence");

			$generateInvoiceNumberFromServer = DB::table($chainSettingsTable)
				->where('chainRefID', $chainID)
				->value('generateInvoiceNumberFromServer');

			if ((int)$generateInvoiceNumberFromServer !== 1) {
				$this->logger->info("Skipping server invoice sequence reset for chain {$chainID}: generateInvoiceNumberFromServer is disabled");
				return [
					'status' => true,
					'message' => "Server invoice sequence reset skipped for chain {$chainID}"
				];
			}

			if (!Schema::hasTable($invoiceSequenceTable)) {
				$referenceTableName = Constants::getChainTableName(1, "invoiceSequence");
				if (!Schema::hasTable($referenceTableName)) {
					throw new Exception("Reference invoice sequence table missing: {$referenceTableName}");
				}

				DB::statement(createTableSchema($referenceTableName, $invoiceSequenceTable));
				$this->logger->info("Created missing invoice sequence table {$invoiceSequenceTable} for chain {$chainID}");
			}

			$stores = DB::table($listOfStoresTable)
				->where('chainID', $chainID)
				->where('isActive', 1)
				->select('storeID')
				->get();

			$seededRows = 0;
			foreach ($stores as $store) {
				foreach ([0, 1] as $isNoCharge) {
					foreach ([0, 1] as $isRefund) {
						$existingRow = DB::table($invoiceSequenceTable)
							->where('storeID', $store->storeID)
							->where('isNoCharge', $isNoCharge)
							->where('isRefund', $isRefund)
							->where('resetDate', $fiscalResetDate)
							->first();

						$payload = [
							'lastInvoiceNumber' => 0,
							'updatedAt' => Carbon::now()
						];

						if ($existingRow) {
							DB::table($invoiceSequenceTable)
								->where('ID', $existingRow->ID)
								->update($payload);
						} else {
							$payload['storeID'] = $store->storeID;
							$payload['isNoCharge'] = $isNoCharge;
							$payload['isRefund'] = $isRefund;
							$payload['resetDate'] = $fiscalResetDate;
							$payload['createdAt'] = Carbon::now();
							DB::table($invoiceSequenceTable)->insert($payload);
						}

						$seededRows++;
					}
				}
			}

			$this->logger->info("Seeded {$seededRows} server invoice sequence rows for chain {$chainID} and fiscal reset date {$fiscalResetDate}");

			return [
				'status' => true,
				'message' => "Reset server invoice sequences for chain {$chainID}",
				'seededRows' => $seededRows
			];
		});
	}
