{"name":"generateInvoiceNumber","qualified_name":"Users-naman-Documents-QBApps-qbapi.app.Services.InvoiceNumberService.InvoiceNumberService.generateInvoiceNumber","label":"Method","file_path":"/Users/naman/Documents/QBApps/qbapi/app/Services/InvoiceNumberService.php","start_line":167,"end_line":420,"source":"	public function generateInvoiceNumber($invoiceSequenceTable, $chainID, $storeID, $isNoCharge, $storeDetail, $today, $isRefund = 0, $isNoInvoiceSale = 0)
	{
		// Validate inputs
		$validation = $this->validateInputs($storeID, $isNoCharge, $isRefund, $isNoInvoiceSale, $storeDetail, $today);
		if (!$validation['valid']) {
			return [
				'status' => false,
				'message' => $validation['message'],
				'error_code' => 'INVALID_INPUT'
			];
		}

		// Validate store prefixes
		$prefixValidation = $this->validateStorePrefixes($storeDetail, $isNoCharge, $isRefund, $isNoInvoiceSale);
		if (!$prefixValidation['valid']) {
			return [
				'status' => false,
				'message' => $prefixValidation['message'],
				'error_code' => 'INVALID_STORE_PREFIX'
			];
		}

		try {
			// Get the appropriate prefix based on charge type, refund status, and no-invoice-sale flag
			if ($isRefund == 1) {
				if ($isNoInvoiceSale == 1) {
					$customStoreOrderPrefix = $storeDetail['RWICustomStoreOrderPrefix'];
				} else {
					$customStoreOrderPrefix = $isNoCharge == 1
						? $storeDetail['NCRefundCustomStoreOrderPrefix']
						: $storeDetail['refundCustomStoreOrderPrefix'];
				}
			} else {
				$customStoreOrderPrefix = $isNoCharge == 1
					? $storeDetail['NCCustomStoreOrderPrefix']
					: $storeDetail['customStoreOrderPrefix'];
			}

			$storeTransactionResetDate = $storeDetail['storeTransactionResetDate'];

			// Get the separator for invoice number formatting
			$separator = $this->getInvoiceNumberSeparator($storeDetail);

			// DATA VALIDATION: Check for any NULL resetDate values (should not exist after migration)
			// This helps catch drift if any external scripts write NULL values
			$nullCheck = DB::table($invoiceSequenceTable)
				->where('storeID', $storeID)
				->where('isNoCharge', $isNoCharge)
				->where('isRefund', $isRefund)
				->whereNull('resetDate')
				->count();

			if ($nullCheck > 0) {
				Log::warning("Found NULL resetDate in invoice sequence table - migration may not have run", [
					'tableName' => $invoiceSequenceTable,
					'storeID' => $storeID,
					'isNoCharge' => $isNoCharge,
					'isRefund' => $isRefund,
					'nullCount' => $nullCheck
				]);
			}

			// Work within the existing transaction and use row-level locking
			// Lock the invoice sequence record for this store/charge/refund type
			// Uses sentinel value '1970-01-01' for NULL reset dates (enforced by migration)
			$sequence = $this->dbManager->executeWithRetry(function() use ($invoiceSequenceTable, $storeID, $isNoCharge, $isRefund, $storeTransactionResetDate, $today) {
				$query = DB::table($invoiceSequenceTable)
					->where('storeID', $storeID)
					->where('isNoCharge', $isNoCharge)
					->where('isRefund', $isRefund);

				// Add reset date filter if applicable
				if (isset($storeTransactionResetDate) &&
					!empty($storeTransactionResetDate) &&
					$storeTransactionResetDate != null &&
					$storeTransactionResetDate <= $today) {
					$query->where('resetDate', $storeTransactionResetDate);
				} else {
					// Use sentinel value '1970-01-01' for no-reset case
					$query->where('resetDate', '1970-01-01');
				}

				return $query->lockForUpdate()->first();
			}, 2);

			if (!$sequence) {
				// No sequence exists - need to create one
				// CRITICAL: Use INSERT ... ON DUPLICATE KEY UPDATE to handle race condition
				// Always use sentinel value '1970-01-01' for NULL reset dates
				$initialSequence = 1;
				$resetDateValue = (isset($storeTransactionResetDate) &&
									!empty($storeTransactionResetDate) &&
									$storeTransactionResetDate != null &&
									$storeTransactionResetDate <= $today) ? $storeTransactionResetDate : '1970-01-01';

				// Track if this was a new insert or an update (for logging/metrics)
				$wasNewInsert = false;

				// Try to insert, but if another request already inserted, just increment
				$this->dbManager->executeWithRetry(function() use ($invoiceSequenceTable, $storeID, $isNoCharge, $isRefund, $initialSequence, $resetDateValue, &$wasNewInsert) {
					$now = Carbon::now();

					// Use raw query for INSERT ... ON DUPLICATE KEY UPDATE
					// This is atomic and handles the race condition
					// The unique index on (storeID, isNoCharge, isRefund, resetDate)
					// ensures this works correctly with sentinel value '1970-01-01'
					$result = DB::statement("
						INSERT INTO {$invoiceSequenceTable}
						(storeID, isNoCharge, isRefund, lastInvoiceNumber, resetDate, createdAt, updatedAt)
						VALUES (?, ?, ?, ?, ?, ?, ?)
						ON DUPLICATE KEY UPDATE
							lastInvoiceNumber = lastInvoiceNumber + 1,
							updatedAt = ?
					", [
						$storeID,
						$isNoCharge,
						$isRefund,
						$initialSequence,
						$resetDateValue,
						$now,
						$now,
						$now
					]);

					// Check if this was an INSERT (new row) or UPDATE (existing row)
					// If affected rows = 1, it was INSERT; if = 2, it was UPDATE
					$affectedRows = DB::select("SELECT ROW_COUNT() as affected")[0]->affected;
					$wasNewInsert = ($affectedRows == 1);
				}, 2);

				// Now read back the actual sequence number that was assigned
				$sequence = $this->dbManager->executeWithRetry(function() use ($invoiceSequenceTable, $storeID, $isNoCharge, $isRefund, $storeTransactionResetDate, $today) {
					$query = DB::table($invoiceSequenceTable)
						->where('storeID', $storeID)
						->where('isNoCharge', $isNoCharge)
						->where('isRefund', $isRefund);

					// Add reset date filter if applicable
					// Use same sentinel value logic as above
					if (isset($storeTransactionResetDate) &&
						!empty($storeTransactionResetDate) &&
						$storeTransactionResetDate != null &&
						$storeTransactionResetDate <= $today) {
						$query->where('resetDate', $storeTransactionResetDate);
					} else {
						$query->where('resetDate', '1970-01-01');
					}

					return $query->first();
				}, 2);

				$actualSequence = $sequence->lastInvoiceNumber;

				// Format the final invoice number with custom separator
				$customInvoiceNumber = !empty($customStoreOrderPrefix)
					? $customStoreOrderPrefix . $separator . $actualSequence
					: $actualSequence;

				// Use distinct log messages for operational monitoring
				$orderType = $isRefund == 1 ? 'refund' : 'order';
				if ($wasNewInsert) {
					Log::info("New invoice sequence created for {$orderType}", [
						'storeID' => $storeID,
						'isNoCharge' => $isNoCharge,
						'isRefund' => $isRefund,
						'invoiceNumber' => $customInvoiceNumber,
						'sequence' => $actualSequence,
						'tableName' => $invoiceSequenceTable,
						'operation' => 'INSERT'
					]);
				} else {
					Log::info("Invoice sequence incremented for {$orderType} (concurrent creation)", [
						'storeID' => $storeID,
						'isNoCharge' => $isNoCharge,
						'isRefund' => $isRefund,
						'invoiceNumber' => $customInvoiceNumber,
						'sequence' => $actualSequence,
						'tableName' => $invoiceSequenceTable,
						'operation' => 'UPDATE'
					]);
				}

				return [
					'status' => true,
					'invoiceNumber' => $customInvoiceNumber,
					'message' => $wasNewInsert ? 'New invoice sequence created' : 'Invoice number generated successfully'
				];
			}

			// Get next invoice number from existing sequence
			$nextInvoiceNumber = $sequence->lastInvoiceNumber + 1;

			// Update sequence
			$this->dbManager->executeWithRetry(function() use ($invoiceSequenceTable, $storeID, $isNoCharge, $isRefund, $nextInvoiceNumber, $storeTransactionResetDate, $today) {
				$query = DB::table($invoiceSequenceTable)
					->where('storeID', $storeID)
					->where('isNoCharge', $isNoCharge)
					->where('isRefund', $isRefund);

				// Add reset date filter if applicable
				// Use sentinel value '1970-01-01' for no-reset case
				if (isset($storeTransactionResetDate) &&
					!empty($storeTransactionResetDate) &&
					$storeTransactionResetDate != null &&
					$storeTransactionResetDate <= $today) {
					$query->where('resetDate', $storeTransactionResetDate);
				} else {
					$query->where('resetDate', '1970-01-01');
				}

				return $query->update([
					'lastInvoiceNumber' => $nextInvoiceNumber,
					'updatedAt' => Carbon::now()
				]);
			}, 2);

			// Format the final invoice number with custom separator
			$customInvoiceNumber = !empty($customStoreOrderPrefix)
				? $customStoreOrderPrefix . $separator . $nextInvoiceNumber
				: $nextInvoiceNumber;

			$orderType = $isRefund == 1 ? 'refund' : 'order';
			Log::info("Invoice number generated successfully for {$orderType}", [
				'storeID' => $storeID,
				'isNoCharge' => $isNoCharge,
				'isRefund' => $isRefund,
				'invoiceNumber' => $customInvoiceNumber,
				'sequence' => $nextInvoiceNumber,
				'tableName' => $invoiceSequenceTable
			]);

			return [
				'status' => true,
				'invoiceNumber' => $customInvoiceNumber,
				'message' => 'Invoice number generated successfully'
			];

		} catch (\Exception $e) {
			Log::error("Error generating invoice number", [
				'storeID' => $storeID,
				'isNoCharge' => $isNoCharge,
				'isRefund' => $isRefund,
				'tableName' => $invoiceSequenceTable,
				'error' => $e->getMessage(),
				'trace' => $e->getTraceAsString()
			]);

			return [
				'status' => false,
				'message' => 'Error generating invoice number: ' . $e->getMessage(),
				'error_code' => 'INVOICE_GENERATION_FAILED'
			];
		}
	}
