{"name":"processChainFiscalYearChange","qualified_name":"Users-naman-Documents-QBApps-qbapi.app.Services.FiscalYearManager.FiscalYearManager.processChainFiscalYearChange","label":"Method","file_path":"/Users/naman/Documents/QBApps/qbapi/app/Services/FiscalYearManager.php","start_line":140,"end_line":222,"source":"	public function processChainFiscalYearChange($chain) {
		try {
			$this->logger->info("Processing fiscal year change for chain: {$chain->chainID} - {$chain->chainName}");

			// Get all active devices for the chain
			$devices = $this->getChainDevices($chain->chainID);

			// Get tomorrow's date to use as sequence start
			$tomorrow = Carbon::tomorrow()->format('Y-m-d');

			// Apply the saved fiscal year prefixes to chain and store settings
			$this->applyFiscalYearPrefixes($chain->chainID);
			$this->resetServerGeneratedInvoiceSequences($chain->chainID, $tomorrow);

			if (empty($devices)) {
				$this->logger->info("No active devices found for chain {$chain->chainID}; fiscal settings were still rolled over");
				return [
					'status' => true,
					'message' => "Fiscal settings rolled over for chain {$chain->chainID} with no active devices",
					'processedDevices' => 0
				];
			}

			$processedDevices = 0;
			$failedDevices = [];
			$allDeviceIDs = [];
			$devicesInfoTable = Constants::getGlobalTableName("devicesInfo");
			foreach ($devices as $device) {
				try {
					// Reset invoice numbers for this device
					$resetResult = $this->resetDeviceInvoiceNumbers($chain->chainID, $device->storeID, $device->deviceID, $tomorrow);
					$allDeviceIDs[] = $device->deviceID;
					// Only update device flags if reset was successful
					if ($resetResult['status']) {
						$this->updateDeviceFiscalFlags($device->deviceID);
						$processedDevices++;
					} else {
						$failedDevices[] = [
							'deviceID' => $device->deviceID,
							'storeID' => $device->storeID,
							'error' => $resetResult['message']
						];
					}
				} catch (Exception $e) {
					$this->logger->error("Error processing device {$device->deviceID}: " . $e->getMessage());
					$failedDevices[] = [
						'deviceID' => $device->deviceID,
						'storeID' => $device->storeID,
						'error' => $e->getMessage()
					];
				}
			}

			// Update device flags in batch using the database manager
			if (!empty($allDeviceIDs)) {
				$this->dbManager->executeWithRetry(function () use ($devicesInfoTable, $allDeviceIDs) {
					$forceSyncTime = Carbon::now()->format('Y-m-d H:i:s');
					$result = DB::table($devicesInfoTable)
						->whereIn('deviceID', $allDeviceIDs)
						->update([
							'isFiscalSettingSynced' => 0,
							'forceSync' => 1,
							'forceSyncTime' => $forceSyncTime
						]);

					$this->logger->info("Updated fiscal settings sync flag and forceSync for " . count($allDeviceIDs) . " devices");
					return $result;
				});
			}

			$this->logger->info("Completed fiscal year change processing for chain: {$chain->chainID}. Processed {$processedDevices} devices.");

			return [
				'status' => true,
				'message' => "Processed {$processedDevices} devices for chain {$chain->chainID}",
				'processedDevices' => $processedDevices,
				'failedDevices' => $failedDevices
			];
		} catch (Exception $e) {
			$this->logger->error("Error processing fiscal year change for chain {$chain->chainID}: " . $e->getMessage());
			throw $e;
		}
	}
