				->where('listOfChains.isActive', 1)
				->select('listOfChains.chainID', 'listOfChains.brandName as chainName', 'fiscalYearStart')
				->get();

			$this->logger->info("Found " . count($chains) . " chains with fiscal year starting tomorrow (" . $tomorrowMMDD . ")");

			return $chains;
		});
	}
