{"name":"savePrefixesForFiscalYear","qualified_name":"Users-naman-Documents-QBApps-qbapi.app.Services.FiscalYearManager.FiscalYearManager.savePrefixesForFiscalYear","label":"Method","file_path":"/Users/naman/Documents/QBApps/qbapi/app/Services/FiscalYearManager.php","start_line":671,"end_line":806,"source":"	public function savePrefixesForFiscalYear($chainID, $fiscalYear, $data) {
		return $this->dbManager->executeWithRetry(function () use ($chainID, $fiscalYear, $data) {
			$this->logger->info("Saving custom prefixes for chain: {$chainID}, fiscal year: {$fiscalYear}");

			$fiscalYearPrefixesTable = Constants::getGlobalTableName("fiscalYearPrefixes");

			// Validate fiscal year format (YYYY-MM-DD)	
			if (!preg_match('/^\d{4}-\d{2}-\d{2}$/', $fiscalYear)) {
				return [
					'status' => false,
					'message' => "Invalid fiscal year format. Expected: YYYY-MM-DD"
				];
			}

			$storeID = isset($data['storeID']) ? $data['storeID'] : 0;
			$listOfStoresTable = Constants::getGlobalTableName('listOfStores');
			$chainUsesStorePrefixes = DB::table($listOfStoresTable)
				->where('chainID', $chainID)
				->where('isActive', 1)
				->whereNotNull('customStoreOrderPrefix')
				->where('customStoreOrderPrefix', '!=', '')
				->exists();

			if ($chainUsesStorePrefixes && (int) $storeID <= 0) {
				return [
					'status' => false,
					'message' => 'This chain uses store prefixes. Fiscal year prefixes must be saved per store.',
				];
			}

			// Check if the entry already exists
			$existingEntry = DB::table($fiscalYearPrefixesTable)
				->where('chainID', $chainID)
				->where('storeID', $storeID)
				->where('fiscalYear', $fiscalYear)
				->first();

			$storePrefixFields = [
				'customOrderPrefix' => 'order prefix',
				'customRefundOrderPrefix' => 'refund prefix',
				'NCCustomStoreOrderPrefix' => 'no-charge order prefix',
				'NCRefundCustomStoreOrderPrefix' => 'no-charge refund prefix',
				'RWICustomStoreOrderPrefix' => 'refund without invoice prefix',
			];

			if ($storeID > 0) {
				foreach ($storePrefixFields as $column => $label) {
					$value = isset($data[$column]) ? trim($data[$column]) : "";
					if ($value === "") {
						continue;
					}

					$duplicateQuery = DB::table($fiscalYearPrefixesTable)
						->where('chainID', $chainID)
						->where('fiscalYear', $fiscalYear)
						->where($column, $value)
						->where('storeID', '>', 0)
						->where('storeID', '!=', $storeID);

					$duplicate = $duplicateQuery->first();
					if (!$duplicate) {
						continue;
					}

					$conflictStore = DB::table($listOfStoresTable)
						->select('storeName')
						->where('chainID', $chainID)
						->where('storeID', $duplicate->storeID)
						->first();

					$storeLabel = $conflictStore ? $conflictStore->storeName : "ID {$duplicate->storeID}";

					return [
						'status' => false,
						'message' => "The {$label} '{$value}' is already used by store {$storeLabel} ({$duplicate->storeID}) for fiscal year {$fiscalYear}.",
					];
				}
			}

			$prefixData = [
				'chainID' => $chainID,
				'storeID' => isset($data['storeID']) ? $data['storeID'] : 0,
				'fiscalYear' => $fiscalYear,
				'customOrderPrefix' => isset($data['customOrderPrefix']) ? $data['customOrderPrefix'] : null,
				'customRefundOrderPrefix' => isset($data['customRefundOrderPrefix']) ? $data['customRefundOrderPrefix'] : null,
				'NCCustomStoreOrderPrefix' => isset($data['NCCustomStoreOrderPrefix']) ? $data['NCCustomStoreOrderPrefix'] : null,
				'NCRefundCustomStoreOrderPrefix' => isset($data['NCRefundCustomStoreOrderPrefix']) ? $data['NCRefundCustomStoreOrderPrefix'] : null,
				'RWICustomStoreOrderPrefix' => isset($data['RWICustomStoreOrderPrefix']) ? $data['RWICustomStoreOrderPrefix'] : null,
				'isActive' => true,
				'updatedAt' => Carbon::now()
			];

			if ($existingEntry) {
				// Update existing entry
				$prefixData['updatedAt'] = Carbon::now();

				// Deactivate all other prefixes for this chain/store combination
				DB::table($fiscalYearPrefixesTable)
					->where('chainID', $chainID)
					->where('storeID', isset($data['storeID']) ? $data['storeID'] : 0)
					->where('id', '!=', $existingEntry->id)
					->update(['isActive' => false]);

				// Update this entry
				DB::table($fiscalYearPrefixesTable)
					->where('id', $existingEntry->id)
					->update($prefixData);

				$this->ensureFiscalYearStartSetting($chainID, $fiscalYear);

				return [
					'status' => true,
					'message' => "Updated fiscal year prefixes for chain ID: {$chainID}, fiscal year: {$fiscalYear}"
				];
			} else {
				// Insert new entry
				$prefixData['createdAt'] = Carbon::now();

				// Deactivate all other prefixes for this chain/store combination
				DB::table($fiscalYearPrefixesTable)
					->where('chainID', $chainID)
					->where('storeID', isset($data['storeID']) ? $data['storeID'] : 0)
					->update(['isActive' => false]);

				// Create new entry
				DB::table($fiscalYearPrefixesTable)->insert($prefixData);

				$this->ensureFiscalYearStartSetting($chainID, $fiscalYear);

				return [
					'status' => true,
					'message' => "Saved new fiscal year prefixes for chain ID: {$chainID}, fiscal year: {$fiscalYear}"
				];
			}
		});
	}
