{"name":"applyFiscalYearPrefixes","qualified_name":"Users-naman-Documents-QBApps-qbapi.app.Services.FiscalYearManager.FiscalYearManager.applyFiscalYearPrefixes","label":"Method","file_path":"/Users/naman/Documents/QBApps/qbapi/app/Services/FiscalYearManager.php","start_line":417,"end_line":572,"source":"	public function applyFiscalYearPrefixes($chainID, $fiscalYear = null) {
		return $this->dbManager->executeWithRetry(function () use ($chainID, $fiscalYear) {
			$this->logger->info("Applying fiscal year prefixes for chain: {$chainID}" . ($fiscalYear ? " and fiscal year: {$fiscalYear}" : ""));

			$listOfChainsTable = Constants::getGlobalTableName("listOfChains");
			$chainSettingsTable = Constants::getGlobalTableName("chainSettings");
			$listOfStoresTable = Constants::getGlobalTableName("listOfStores");
			$fiscalYearPrefixesTable = Constants::getGlobalTableName("fiscalYearPrefixes"); // This will resolve to globalFiscalYearPrefixes

			// Define currentYear variable for use in both if and later code
			$currentYear = Carbon::tomorrow()->year;

			// Only calculate fiscal year if not provided
			if ($fiscalYear === null) {
				// Get chain fiscal year start date (format: mmdd)
				$chainSettings = DB::table($chainSettingsTable)
					->where('chainRefID', $chainID)
					->select('fiscalYearStart')
					->first();

				if (!$chainSettings) {
					$this->logger->error("Chain settings not found for chain ID: {$chainID}");
					return [
						'status' => false,
						'message' => "Chain settings not found"
					];
				}

				// Calculate the fiscal year based on tomorrow's date
				$tomorrow = Carbon::tomorrow();
				$fiscalStartMMDD = $chainSettings->fiscalYearStart;
				// Format with a dash between month and day for YYYY-MM-DD format
				$month = substr($fiscalStartMMDD, 0, 2);
				$day = substr($fiscalStartMMDD, 2, 2);
				$fiscalYear = $currentYear . '-' . $month . '-' . $day;
			}

			$fiscalResetDate = $fiscalYear;
			DB::table($listOfStoresTable)
				->where('chainID', $chainID)
				->update([
					'storeTransactionResetDate' => $fiscalResetDate
				]);
			$this->logger->info("Applied fiscal reset date {$fiscalResetDate} to all stores for chain {$chainID}");

			// Get active prefixes for this chain and fiscal year
			$activePrefixes = DB::table($fiscalYearPrefixesTable)
				->where('chainID', $chainID)
				->where('fiscalYear', $fiscalYear)
				->where('isActive', true)
				->get();

			$this->logger->info("Active prefixes for chain ID: {$chainID} and fiscal year: {$fiscalYear}");
			$this->logger->info("Active prefixes: " . json_encode($activePrefixes));

			// Check if there are no active prefixes (handle both Collection and array)
			if (empty($activePrefixes) || (is_object($activePrefixes) && method_exists($activePrefixes, 'isEmpty') && $activePrefixes->isEmpty())) {
				$this->logger->notice("No active prefixes found for chain ID: {$chainID} and fiscal year: {$fiscalYear}");
				// Use default prefixes
				// Example: OR26 | RF26
				$nextYear = $currentYear + 1;
				$prefixYears = substr($nextYear, -2);
				$defaultPrefixes = [
					'customOrderPrefix' => "OR{$prefixYears}",
					'customRefundOrderPrefix' => "RF{$prefixYears}"
				];

				// Update chain settings with default prefixes
				DB::table($listOfChainsTable)
					->where('chainID', $chainID)
					->update([
						'customOrderPrefix' => $defaultPrefixes['customOrderPrefix'],
						'customRefundOrderPrefix' => $defaultPrefixes['customRefundOrderPrefix']
					]);
				// return
				return [
					'status' => true,
					'message' => "Default prefixes applied for chain ID: {$chainID}"
				];
			}

			$this->logger->info("Found " . count($activePrefixes) . " active prefixes to apply");

			// Apply chain level prefixes if found
			$chainPrefixes = null;
			// Handle both Collection and array
			if (is_object($activePrefixes) && method_exists($activePrefixes, 'where')) {
				$chainPrefixes = $activePrefixes->where('storeID', 0)->first();
			} else {
				// Handle as array
				foreach ($activePrefixes as $prefix) {
					if ($prefix->storeID == 0) {
						$chainPrefixes = $prefix;
						break;
					}
				}
			}
			if ($chainPrefixes) {
				$this->logger->info("Applying chain-level prefixes for chain ID: {$chainID}");

				DB::table($listOfChainsTable)
					->where('chainID', $chainID)
					->update([
						'customOrderPrefix' => $chainPrefixes->customOrderPrefix,
						'customRefundOrderPrefix' => $chainPrefixes->customRefundOrderPrefix
					]);
			}
			// check if non chain level prefixes are present (store ID non 0)
			$nonChainPrefixes = [];

			// Handle both Collection and array
			if (is_object($activePrefixes) && method_exists($activePrefixes, 'where')) {
				$nonChainPrefixes = $activePrefixes->where('storeID', '!=', 0);
			} else {
				// Handle as array
				foreach ($activePrefixes as $prefix) {
					if ($prefix->storeID != 0) {
						$nonChainPrefixes[] = $prefix;
					}
				}
			}

			if (empty($nonChainPrefixes) || (is_object($nonChainPrefixes) && method_exists($nonChainPrefixes, 'isEmpty') && $nonChainPrefixes->isEmpty())) {
				$this->logger->info("No non-chain level prefixes found for chain ID: {$chainID}");
				// return
				return [
					'status' => true,
					'message' => "Prefix applied successfully for chain ID: {$chainID}"
				];
			}

			$this->logger->info("Found " . count($nonChainPrefixes) . " non-chain level prefixes to apply");
			$storeCount = 0;
			foreach ($nonChainPrefixes as $prefix) {
				DB::table($listOfStoresTable)
					->where('storeID', $prefix->storeID)
					->update([
						'customStoreOrderPrefix' => $prefix->customOrderPrefix,
						'refundCustomStoreOrderPrefix' => $prefix->customRefundOrderPrefix,
						'NCCustomStoreOrderPrefix' => $prefix->NCCustomStoreOrderPrefix,
						'NCRefundCustomStoreOrderPrefix' => $prefix->NCRefundCustomStoreOrderPrefix,
						'RWICustomStoreOrderPrefix' => $prefix->RWICustomStoreOrderPrefix
					]);
				$storeCount++;
			}

			$this->logger->info("Saved fiscal year prefixes for chain {$chainID}: 1 chain record and {$storeCount} store records");

			return [
				'status' => true,
				'message' => "Saved fiscal year prefixes for chain {$chainID}",
				'chainCount' => 1,
				'storeCount' => $storeCount
			];
		});
	}
