{"name":"executeWithRetry","qualified_name":"Users-naman-Documents-QBApps-qbapi.app.Services.DatabaseManager.DatabaseManager.executeWithRetry","label":"Method","file_path":"/Users/naman/Documents/QBApps/qbapi/app/Services/DatabaseManager.php","start_line":25,"end_line":57,"source":"    public function executeWithRetry(callable $operation, $retries = null, $backoff = null)
    {
        $retries = $retries ?? $this->maxRetries;
        $backoff = $backoff ?? $this->initialBackoff;

        $attempt = 0;

        while ($attempt <= $retries) {
            try {
                return $operation();
            } catch (QueryException $e) {
                // Check if this is a deadlock or lock wait timeout
                if ($this->isDeadlockError($e) && $attempt < $retries) {
                    $attempt++;

                    // Exponential backoff with jitter
                    $sleepMs = min($backoff * pow(2, $attempt) + rand(0, 100), $this->maxBackoff);
                    $sleepSeconds = $sleepMs / 1000;

                    Log::warning("Database operation failed (attempt {$attempt}/{$retries}). Retrying in {$sleepSeconds} seconds. Error: " . $e->getMessage());

                    usleep($sleepMs * 1000); // usleep uses microseconds
                    continue;
                }

                // Rethrow if not a deadlock or out of retries
                throw $e;
            } catch (Exception $e) {
                Log::error("Database operation failed: " . $e->getMessage());
                throw $e;
            }
        }
    }
