{"name":"forceFiscalYearChange","qualified_name":"Users-naman-Documents-QBApps-qbapi.app.Http.Controllers.FiscalYearController.FiscalYearController.forceFiscalYearChange","label":"Method","file_path":"/Users/naman/Documents/QBApps/qbapi/app/Http/Controllers/FiscalYearController.php","start_line":32,"end_line":76,"source":"    public function forceFiscalYearChange(Request $request)
    {
        $result = $request->getContent();

        if (isJson($result) == FALSE) {
            $response = ["message" => "Invalid Data"];
            return response()->json($response, 422, [], JSON_NUMERIC_CHECK);
        }

        $data = convertToArray(json_decode($result));

        // Validate required parameters
        if (!isset($data['chainID'])) {
            $response = ["message" => "Chain ID is required"];
            return response()->json($response, 422, [], JSON_NUMERIC_CHECK);
        }

        $chainID = $data['chainID'];

        try {
            // Get chain details
            $chain = $this->getChainDetails($chainID);

            if (!$chain) {
                $response = ["message" => "Chain ID {$chainID} not found"];
                return response()->json($response, 404, [], JSON_NUMERIC_CHECK);
            }

            // Process fiscal year change for the chain
            $result = $this->fiscalYearManager->processChainFiscalYearChange($chain);

            Log::info("Manual fiscal year change triggered for chain: {$chainID}", $result);

            return response()->json($result, 200, [], JSON_NUMERIC_CHECK);
        } catch (\Exception $e) {
            Log::error("Error in manual fiscal year change: " . $e->getMessage());

            $response = [
                "status" => false,
                "message" => "Error processing fiscal year change: " . $e->getMessage()
            ];

            return response()->json($response, 500, [], JSON_NUMERIC_CHECK);
        }
    }
